<span class="line"><span style="color:#9399B2;">            [</span><span style="color:#A6E3A1;">&quot;bash&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;--norc&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;--noprofile&quot;</span><span style="color:#9399B2;">],</span></span>
